52	    /// Import a .hdpack (ZIP) file.
53	    pub fn import(zip_path: &Path) -> Result<Self> {
54	        let file = std::fs::File::open(zip_path)?;
55	        let mut archive = zip::ZipArchive::new(file)?;
56	        
57	        // Find pack.yaml to get the pack name
58	        let mut pack_yaml_content = String::new();
59	        {
60	            let mut file = archive.by_name("pack.yaml")
61	                .context("ZIP archive missing pack.yaml")?;
62	            use std::io::Read;
63	            file.read_to_string(&mut pack_yaml_content)?;
64	        }
65	        
66	        let pack: Pack = serde_yaml_ng::from_str(&pack_yaml_content)
67	            .context("Failed to parse pack.yaml from ZIP")?;
68	        
69	        let dest_dir = get_profiles_dir()?.join(&pack.name);
70	        if dest_dir.exists() {
71	            std::fs::remove_dir_all(&dest_dir)?;
72	        }
73	        std::fs::create_dir_all(&dest_dir)?;
74	
75	        // Extract all files with path traversal protection
76	        for i in 0..archive.len() {
77	            let mut file = archive.by_index(i)?;
78	            let outpath = match file.enclosed_name() {
79	                Some(path) => dest_dir.join(path),
80	                None => continue,
81	            };
82	
83	            if (*file.name()).ends_with('/') {
84	                std::fs::create_dir_all(&outpath)?;
85	            } else {
86	                if let Some(p) = outpath.parent() {
87	                    if !p.exists() {
88	                        std::fs::create_dir_all(&p)?;
89	                    }
90	                }
91	                let mut outfile = std::fs::File::create(&outpath)?;
92	                std::io::copy(&mut file, &mut outfile)?;
93	            }
94	        }
95	
96	        Ok(pack)
97	    }
98	
99	    /// Export a pack to a .hdpack (ZIP) file.
100	    pub fn export(&self, source_dir: &Path, dest_path: &Path) -> Result<()> {
101	        let file = std::fs::File::create(dest_path)?;
102	        let mut zip = zip::ZipWriter::new(file);
103	        let options = zip::write::FileOptions::default()
104	            .compression_method(zip::CompressionMethod::Stored);
105	
106	        // Write pack.yaml
107	        zip.start_file("pack.yaml", options)?;
108	        let yaml = serde_yaml_ng::to_string(self)?;
109	        use std::io::Write;
110	        zip.write_all(yaml.as_bytes())?;
111	
112	        // Copy sounds/ directory if it exists in the profile dir
113	        let sounds_dir = source_dir.join("sounds");
114	        if sounds_dir.exists() && sounds_dir.is_dir() {
115	            Self::add_dir_to_zip(&mut zip, &sounds_dir, Path::new("sounds"), options)?;
116	        }
117	        
118	        zip.finish()?;
119	        Ok(())
120	    }
121	
122	    fn add_dir_to_zip<W: std::io::Write + std::io::Seek>(
123	        zip: &mut zip::ZipWriter<W>,
124	        real_path: &Path,
125	        zip_path: &Path,
126	        options: zip::write::FileOptions,
127	    ) -> Result<()> {
128	        for entry in std::fs::read_dir(real_path)? {
129	            let entry = entry?;
130	            let path = entry.path();
131	            let name = entry.file_name();
132	            let new_zip_path = zip_path.join(name);
133	
134	            if path.is_dir() {
135	                // ZIP directories must end with /
136	                let mut dir_name = new_zip_path.to_string_lossy().into_owned();
137	                if !dir_name.ends_with('/') {
138	                    dir_name.push('/');
139	                }
140	                zip.add_directory(dir_name, options)?;
141	                Self::add_dir_to_zip(zip, &path, &new_zip_path, options)?;
142	            } else {
143	                zip.start_file(new_zip_path.to_string_lossy(), options)?;
144	                let mut f = std::fs::File::open(path)?;
145	                std::io::copy(&mut f, zip)?;
146	            }
147	        }
148	        Ok(())
149	    }
150	}
