278	/// Return the XDG config file path (D-14), creating the config directory if needed.
279	/// $XDG_CONFIG_HOME/hd-linux-voice/config.yaml, or ~/.config/hd-linux-voice/config.yaml.
280	pub fn default_config_path() -> Result<PathBuf> {
281	    let xdg = xdg::BaseDirectories::with_prefix("hd-linux-voice");
282	    xdg.place_config_file("config.yaml")
283	        .context("Failed to create XDG config directory for hd-linux-voice")
284	}
285	
286	/// Load and deserialize config from the given path (or XDG default).
287	/// Returns Err with an actionable message on any parse or I/O failure.
288	pub fn load(path_override: Option<&std::path::Path>) -> Result<Config> {
289	    let path = match path_override {
290	        Some(p) => p.to_path_buf(),
291	        None => default_config_path()?,
292	    };
293	
294	    let file = std::fs::File::open(&path).with_context(|| {
295	        format!(
296	            "Config file not found: {}\n\
297	             Create it at that path. See config.example.yaml for the format.",
298	            path.display()
299	        )
300	    })?;
301	
302	    let config: Config = serde_yaml_ng::from_reader(file).with_context(|| {
303	        format!("Failed to parse config file: {}", path.display())
304	    })?;
305	
306	    Ok(config)
307	}
